import{_ as n,o as e,c as t,ag as s}from"./chunks/framework.ePeAWSvT.js";const h=JSON.parse('{"title":"架构概览","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture/index.md","filePath":"guide/architecture/index.md"}'),r={name:"guide/architecture/index.md"};function o(p,a,d,l,i,c){return e(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="架构概览" tabindex="-1">架构概览 <a class="header-anchor" href="#架构概览" aria-label="Permalink to &quot;架构概览&quot;">​</a></h1><p>本文描述 XnneHangLab 主项目（<code>src/lab/</code>）的整体分层与模块职责，帮助开发者快速定位代码。</p><h2 id="分层结构" tabindex="-1">分层结构 <a class="header-anchor" href="#分层结构" aria-label="Permalink to &quot;分层结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/lab/</span></span>
<span class="line"><span>├── 入口层</span></span>
<span class="line"><span>│   ├── server.py                 # FastAPI 服务（主入口，WebSocket + HTTP API）</span></span>
<span class="line"><span>│   └── streamlit/app.py              # Streamlit WebUI 入口（页面路由）</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── 通信层</span></span>
<span class="line"><span>│   ├── websocket_handler.py      # WebSocket 协议处理</span></span>
<span class="line"><span>│   └── message_handler.py        # 消息事件总线</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── 对话层</span></span>
<span class="line"><span>│   ├── conversations/            # 对话编排、TTS 管理、中断处理</span></span>
<span class="line"><span>│   └── service_context.py        # 会话上下文（Agent + 配置）</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── 智能体层</span></span>
<span class="line"><span>│   ├── agent/                    # Agent 框架（LLM 调用、记忆管理）</span></span>
<span class="line"><span>│   └── mcp/                      # 工具调用（MCP 协议）</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>└── 基础设施层</span></span>
<span class="line"><span>    ├── api/                      # HTTP 路由 &amp; TTS/ASR 客户端</span></span>
<span class="line"><span>    ├── asr/                      # 语音识别（FunASR / Whisper）</span></span>
<span class="line"><span>    ├── config_manager/           # 配置管理（TOML 加载）</span></span>
<span class="line"><span>    ├── logger/                   # 分组日志</span></span>
<span class="line"><span>    ├── streamlit/                # Streamlit UI 页面与样式</span></span>
<span class="line"><span>    │   ├── app.py                # 页面路由入口（原 ui.py）</span></span>
<span class="line"><span>    │   ├── style.py              # 全局 CSS 样式注入</span></span>
<span class="line"><span>    │   ├── i18n.py               # UI i18n 枚举（Device / Guide / SubtitleSpeed 等）</span></span>
<span class="line"><span>    │   ├── session_keys.py       # session_state key 常量</span></span>
<span class="line"><span>    │   ├── project/              # 主功能页（主页、音频识别）</span></span>
<span class="line"><span>    │   ├── setting/              # 设置页</span></span>
<span class="line"><span>    │   └── dialogs/              # 对话框组件</span></span>
<span class="line"><span>    ├── utils/                    # 工具函数（音频处理、文本工具）</span></span>
<span class="line"><span>    └── cli.py                    # CLI 工具（ASR 命令行）</span></span></code></pre></div><p><strong>外部客户端：</strong></p><ul><li><a href="https://github.com/XnneHangLab/Open-LLM-VTuber-Web" target="_blank" rel="noreferrer">Open-LLM-VTuber-Web</a> — VTuber 前端（WebSocket 连接）</li><li><a href="https://github.com/XnneHangLab/AIChat" target="_blank" rel="noreferrer">AIChat</a> — 对话客户端（WebSocket 连接）</li></ul><h2 id="请求流程" tabindex="-1">请求流程 <a class="header-anchor" href="#请求流程" aria-label="Permalink to &quot;请求流程&quot;">​</a></h2><p>一个典型的语音对话请求经过以下路径：</p><ol><li><strong>客户端连接</strong> → <code>server.py</code> 建立 WebSocket 连接</li><li><strong>消息路由</strong> → <code>websocket_handler.py</code> 解析协议，分发到对应处理器</li><li><strong>对话触发</strong> → <code>conversations/</code> 判断对话类型（语音输入 / 文字输入 / 群聊），创建对话任务</li><li><strong>上下文准备</strong> → <code>service_context.py</code> 组装 Agent、加载 Prompt 和 Live2D 模型配置</li><li><strong>Agent 推理</strong> → <code>agent/</code> 调用 LLM，可能触发 MCP 工具循环</li><li><strong>响应生成</strong> → Agent 返回文本，经断句后发送给 TTS</li><li><strong>音频合成</strong> → <code>api/</code> 调用 GPT-SoVITS / Qwen-TTS 生成音频</li><li><strong>回传客户端</strong> → 音频 + 字幕 + Live2D 表情通过 WebSocket 推送</li></ol><h2 id="模块速查" tabindex="-1">模块速查 <a class="header-anchor" href="#模块速查" aria-label="Permalink to &quot;模块速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>路径</th><th>职责</th><th>详情</th></tr></thead><tbody><tr><td><strong>Agent</strong></td><td><code>agent/</code></td><td>LLM 调用、工具循环、记忆存储</td><td><a href="./agent.html">→ agent</a></td></tr><tr><td><strong>API</strong></td><td><code>api/</code></td><td>HTTP 路由、TTS/ASR 客户端封装</td><td><a href="./api.html">→ api</a></td></tr><tr><td><strong>ASR</strong></td><td><code>asr/</code></td><td>FunASR / Whisper 语音识别</td><td><a href="./asr.html">→ asr</a></td></tr><tr><td><strong>MCP</strong></td><td><code>mcp/</code></td><td>MCP 工具服务器、工具注册与路由</td><td><a href="./mcp.html">→ mcp</a></td></tr><tr><td><strong>Conversations</strong></td><td><code>conversations/</code></td><td>对话编排、TTS 管理、中断处理</td><td><a href="./conversations.html">→ conversations</a></td></tr><tr><td><strong>Config</strong></td><td><code>config_manager/</code></td><td>TOML 配置加载与校验</td><td><a href="./config.html">→ config</a></td></tr><tr><td><strong>Live2D</strong></td><td><code>live2d_model.py</code></td><td>Live2D 模型 Payload 构建</td><td>—</td></tr><tr><td><strong>Logger</strong></td><td><code>logger/</code></td><td>分组日志</td><td>—</td></tr><tr><td><strong>Streamlit</strong></td><td><code>streamlit/</code></td><td>Streamlit UI 页面与全局样式</td><td>—</td></tr><tr><td><strong>Utils</strong></td><td><code>utils/</code></td><td>音频处理、文本工具、控制台</td><td>—</td></tr></tbody></table><h2 id="关键设计决策" tabindex="-1">关键设计决策 <a class="header-anchor" href="#关键设计决策" aria-label="Permalink to &quot;关键设计决策&quot;">​</a></h2><h3 id="单一-llm-provider" tabindex="-1">单一 LLM Provider <a class="header-anchor" href="#单一-llm-provider" aria-label="Permalink to &quot;单一 LLM Provider&quot;">​</a></h3><p>项目只保留 OpenAI Compatible 接口。<code>LLMFactory</code> 直接返回 <code>AsyncLLM</code>，不做 provider 分支。所有后端（DeepSeek、Qwen 等）通过 <code>base_url</code> 切换。</p><h3 id="agent-memoryagent" tabindex="-1">Agent = MemoryAgent <a class="header-anchor" href="#agent-memoryagent" aria-label="Permalink to &quot;Agent = MemoryAgent&quot;">​</a></h3><p>当前只有一个 Agent 实现：<code>MemoryAgent</code>。它同时负责对话、工具调用和记忆存储。<code>AgentFactory</code> 存在是为未来多 Agent 预留。</p><h3 id="mcp-工具框架" tabindex="-1">MCP 工具框架 <a class="header-anchor" href="#mcp-工具框架" aria-label="Permalink to &quot;MCP 工具框架&quot;">​</a></h3><p>工具通过 <a href="https://modelcontextprotocol.io/" target="_blank" rel="noreferrer">MCP (Model Context Protocol)</a> 接入，支持远程工具服务器。<code>FastMcpRouter</code> 管理多 server 连接，<code>ToolRegistry</code> 处理工具解析和执行。</p><h3 id="对话中断" tabindex="-1">对话中断 <a class="header-anchor" href="#对话中断" aria-label="Permalink to &quot;对话中断&quot;">​</a></h3><p>支持两种中断模式：个体中断（用户打断 AI 说话）和群聊中断。中断信号通过 <code>MessageHandler</code> 事件总线传递。</p>`,20)])])}const m=n(r,[["render",o]]);export{h as __pageData,m as default};
